1	export type Cell = [number, number];
2	
3	function countNeighbors(cells: Cell[], x: number, y: number): number {
4	  let count = 0;
5	  for (const [cx, cy] of cells) {
6	    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1 && !(cx === x && cy === y)) {
7	      count++;
8	    }
9	  }
10	  return count;
11	}
12	
13	export function nextGeneration(cells: Cell[]): Cell[] {
14	  return cells.filter(([x, y]) => {
15	    const n = countNeighbors(cells, x, y);
16	    return n === 2 || n === 3;
17	  });
18	}
