4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with exactly 2 live neighbors", () => {
15	    // Three cells in a row: center has 2 neighbors → survives
16	    // End cells have 1 neighbor → die
17	    // Dead neighbors of center may also be considered (reproduction rule checked separately)
18	    const gen0: Cell[] = [[0, 0], [1, 0], [2, 0]];
19	    const gen1 = nextGeneration(gen0);
20	    expect(gen1).toContainEqual([1, 0]); // center survives
21	  });
22	  it.todo("should keep a live cell alive with exactly 3 live neighbors");
23	  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
24	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
25	  it.todo("should correctly compute the blinker pattern (oscillator)");
26	  it.todo("should correctly compute the block pattern (still life)");
27	});
